(70, 'Arkansas', 'AEGIS Summer Programs (Academic Enrichment for Gifted/Talented)', '9?12', 'Open to Arkansas students; not required to be formally identified gifted/talented; application required.', 'Funded by DESE via grants; likely low or no cost to student; travel or room/board may or may not be funded depending on residential vs commuter session.', 'For example, AI Robotics & Ethics: application deadline April 5, 2025.', 'https://faculty.uca.edu/wvslaton/AEGIS-Camp/', 'Academic Program', 'Technology / Coding', 'Outside School', 'Some sessions residential, some commuter; high school level; unique focus combining ethics + robotics; selective admission.', '2025-11-12 02:58:02'),
(71, 'Arkansas', 'AR Tech?DaSH (Arkansas Technology & Data Science in Health & Medicine)', '9?12', 'Application required; interest in health, medicine, data science; serves diverse / underserved populations; open statewide.', 'Funded via NIH SEPA grant; costs for students minimal or free; outreach components likely no cost.', 'Summer day camp portion has specific schedule; virtual & outreach parts ongoing; check timeline each year.', 'https://medicine.uams.edu/neuroscience/outreach/ar-tech-dash/', 'Academic Program', 'Health / Medicine', 'Outside School', '10?day day camp; includes virtual outreach; students can serve as STEM ambassadors; encourages long?term involvement.', '2025-11-12 02:58:02'),
(72, 'Arkansas', 'Arkansas 4?H STEM / Science Programs', '6?12', 'Open to youth involved in 4?H; interest in STEM; may require local club membership.', 'Low cost / 4?H membership fees; many programs free or supported by grant funding and county Extension agents.', 'Ongoing; specific projects / events have deadlines; vary by county.', 'https://4h.uada.edu/programs/science/ ', 'Competition', 'Science', 'Through School', 'Provides hands?on projects; opportunities to present; widely available via counties; good for gaining STEM?skill exposure over time.', '2025-11-12 02:58:02'),
