(80, 'Arkansas', 'A?State Engineering Boot Camp', '9?12', 'Interest in engineering; apply; sometimes limited slots; likely open to in?state students though non?resident may be allowed.', 'Cost: Day version ~$300; overnight version ~$450; scholarships / need?based assistance available.', 'Camp in mid?July 2025 (July 14?18); registration deadlines in advance.', 'https://www.astate.edu/college/ecs/outreach-coecs/engrcamp.dot', 'Academic Program', 'Technology / Coding', 'Outside School', 'In?person; includes exposure to labs, faculty, design work; overnight version offers more immersive experience.', '2025-11-12 02:58:02'),
(81, 'Arkansas', 'Camp: ASPIRE ? Arkansas STEM Coalition', '9?12', 'Open to all levels (beginners to experienced) children/students; virtual class enrollment.', 'Fee charged (varies per session); robotics kit included and reusable; scholarships or codes may reduce cost.', 'Offered in summer; registration cycles announced in advance.', 'https://arkansasstemcoalition.com/camp-aspire/', 'Academic Program', 'Technology / Coding', 'Outside School', 'Virtual robotics intensive; families keep robot kit; flexible & accessible; good for low travel burden.', '2025-11-12 02:58:02'),
(82, 'Arkansas', 'UA Little Rock Robotics Camps & VEX IQ Camps', '6?8', 'Interested students; sometimes prior experience beneficial; open registration.', 'Fee (e.g. ~$150 for some camps) for registration; possible scholarships / financial aid depending on host.', 'Summer schedule; e.g. one camp June 16?20, etc. Registration opens in advance; spaces limited.', 'https://eac.ualr.edu/robotics-camp/', 'Academic Program', 'Technology / Coding', 'Outside School', 'In?person; hands?on; includes competition component in robotics; good for building engineering & teamwork skills.', '2025-11-12 02:58:02'),
(83, 'Arkansas', 'UA?PTC Youth Tech Science Camps', '9?12', 'Students entering those grade levels; interest in tech/science; application to the host institution.', 'Cost per camp; likely modest; cost varies by track; sponsors / camp funding may offer aid.', 'Summer camps announced ahead of time; registration deadlines before camp.', 'https://uaptc.edu/tech-science-camp', 'Academic Program', 'Technology / Coding', 'Outside School', 'Hands?on, day camps; focuses include robotics, 3D printing, HVAC, CNC etc; good for students interested in applied tech.', '2025-11-12 02:58:02'),
