(429, 'Colorado', 'Concurrent Enrollment', '9- 12', 'must be at grade level', 'free(responsible for all campus fees, books, materials and transportation not included)', 'Fall semester: May 15 and Spring semester: November 15', 'https://www.jeffcopublicschools.org/learning/career-college-pathways/postsecondary-opportunities/concurrent-enrollment', 'Scholarship', 'Multidisciplinary', 'Through School', 'is a program let\'s eligible high school students take college classes. This gives them head start in life after they graduate ', '2025-11-12 03:04:28'),
(430, 'Colorado', 'Degree Start by  pikes pike college', '11- 12', '(for English)Accuplacer Writing 246 PSAT/SAT EBWR 470 ACT Reading: 17(for Math)Accuplacer Algebra, and Statistics 240 PSAT/SAT Math 500 ACT 19', 'free (books not included)', 'june 1st', 'https://www.pikespeak.edu/academics/high-school-programs/Degree-Start.php', 'Scholarship', 'Multidisciplinary', 'Outside School', 'Degree Start is a pilot program for rising Junior and Senior high school students majoring in a liberal arts field.. There are\r\n12 spots available and after all spots are filled, students will be placed on a waitlist. ', '2025-11-12 03:04:28'),
(431, 'Colorado', 'High School Program by the University of Colorado Denver', '9 -12', 'your parents cannot have a college degree, or must be a single-parent household. or be the eldest ', 'free', 'fall', 'https://www.ucdenver.edu/pre-college/programs/high-school', 'Scholarship', 'Multidisciplinary', 'Outside School', 'This program is designed for students who are going on to college after high school. For eligibility, they must be in high school and first-generation college student, meaning neither of their biological nor adoptive parents completed a four-year college degree. And have a gpa over 2.5. the main aim of the program is to help students go to college .and can even get some college credit ', '2025-11-12 03:04:28'),
(432, 'Colorado', 'Jeffco READS @ Home', 'k-3', 'unspecifed', 'free', 'opens February 10th closes April 4th, ', 'https://www.jeffcopublicschools.org/learning/extended-learning/summer-learning', 'Club', 'Arts', 'Outside School', 'Jeffco READS @ Home is a six-week virtual summer reading program designed to support and strengthen reading skills during the summer months.', '2025-11-12 03:04:28'),
(433, 'Colorado', 'K-12 Summer Programs by  Colorado State University', 'k-12', 'must be at grade level ', 'scholarships ', 'late fall through early spring', 'https://k12summer.colostate.edu/', 'Academic Program', 'Science', 'Outside School', 'It\'s a summer camp for students to get ahead in their classes. If the student is in highschool, they can gain college credit by joining some of these programs. it covers STEM classes.  ', '2025-11-12 03:04:28');
