(1120, 'Wisconsin', 'ARISE High School Cancer Research \r\nProgram', '11', '? Be 16 at the start of the program\r\n? Proof of high school enrollment\r\n? Personal statement\r\n? Letter of recomendation', 'privately funded', 'February 21', 'https://cancer.wisc.edu/research/education/high-school-education/', 'Other (internship)', 'Health', 'Outside School', '? A seven-week summer program in cancer biology with lab work, ethics discussions, professional development, and career exploration\r\n? Provided by the U of Wisconsin\r\n? Interns are paid $15 per hour\r\n? Housing is not provided', '2025-11-12 03:04:34'),
(1121, 'Wisconsin', 'Bellin Nursing & Allied Health Camps', '11-12', '? 16+ years old\r\n? GPA (2.75+)', '$110 fee', 'Rolling admission', 'https://www.bellincollege.edu/admissions/visit/summer-camps/', 'Other (Summer camp)', 'Health', 'Outside school', '? lasts 2 days at Bellin college\r\nCamp includes:\r\n? hospital shadowing\r\n?  panel discussions\r\n? hands-on simulations in nursing and allied health (radiology, sonography, radiation therapy, surgical assisting). ', '2025-11-12 03:04:34'),
(1122, 'Wisconsin', 'Capital (Madison area) Science & \r\nEngineering Fair', '9-12', 'open for all', '? $15 application fee', 'January 15', 'https://dpi.wi.gov/science/science-fairs/csef', 'Competition', 'Science', 'Outside School', 'Participants also compete for an \r\nopportunity to enter the Intel InterUSA Science and Engineering Fair and the Badger State Science & Engineering Fair', '2025-11-12 03:04:34'),
(1123, 'Wisconsin', 'Milwaukee Ballet School Summer Intensive', '9?12', 'Audition required', '$3,500 (Scholarship supported)', 'January 15 (Audition)', 'https://milwaukeeballet.org/summer-intensive-programs', 'Volunteer/Service', '', '', '', '2025-11-12 03:04:34'),
