(1132, 'Wisconsin', 'Wisconsin EMS Student Day (WEMSA', '9-12', 'open to all', '$ 40 fee', 'January 1', 'https://www.wemsaexpo.com/wemsa2026/student-day', 'Other (workshop)', 'Health', 'Outside school', '? Statewide event\r\n? Lunch is included with registration\r\n? One-day event with hands-on learning where students rotate through 30-minute workshops led by EMS professionals.', '2025-11-12 03:04:34'),
(1133, 'Wisconsin', 'Wisconsin Labor History Society \r\nKenneth A. Germanson High School Essay Contest', '9-12', 'open to all', 'privately funded', 'February 15', 'https://www.wisconsinlaborhistory.org/essay-contest/', 'Competition', 'Other', 'Outside school', '? Students submit an essay on the topic ?Unions are good for my family, my community and my nation because . . .?\r\n? Prices of up to $500', '2025-11-12 03:04:34'),
