(1287, 'Maine', 'Maine Medical Center Junior Volunteers Program', 'Ages 14-17', 'Students between the ages of 14-17.', 'Unpaid (volunteer).', 'Year-round.', 'https://www.careersatmainehealth.org/pages/students', 'Volunteer/Service', 'Health / Medicine', 'Outside School', 'A year-round program that offers students the opportunity to volunteer in a hospital setting.', '2025-12-03 00:17:53'),
